diffs.replacement:
@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-gray-900 text-white;
    font-family: 'Inter', sans-serif;
  }
}

import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { UserRole } from '../types';
import { api } from '../services/api';
import { Ticket, PlusCircle, User as UserIcon, ScanLine, Menu, X, Shield, HelpCircle, Heart, Trash2, FileText, LayoutDashboard, Search, Bell, LogOut } from 'lucide-react';

const UniPartyLogo = () => (
  <svg width="40" height="40" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="h-9 w-9">
    <defs>
      <linearGradient id="logo_gradient" x1="0" y1="0" x2="100" y2="100" gradientUnits="userSpaceOnUse">
        <stop offset="0%" stopColor="#3b82f6" />
        <stop offset="100%" stopColor="#ec4899" />
      </linearGradient>
    </defs>
    <g transform="translate(50, 50) rotate(-15) translate(-50, -50)">
      <path 
        d="M25 20 H75 A10 10 0 0 1 85 30 V42 A8 8 0 0 0 85 58 V70 A10 10 0 0 1 75 80 H25 A10 10 0 0 1 15 70 V58 A8 8 0 0 0 15 42 V30 A10 10 0 0 1 25 20 Z" 
        fill="url(#logo_gradient)" 
      />
      <path 
        d="M50 35 L54 45 H65 L56 52 L60 63 L50 56 L40 63 L44 52 L35 45 H46 L50 35 Z" 
        fill="white" 
      />
      <circle cx="65" cy="35" r="2" fill="white" fillOpacity="0.8" />
      <circle cx="35" cy="65" r="2" fill="white" fillOpacity="0.8" />
      <path d="M50 25 V28" stroke="white" strokeWidth="2" strokeLinecap="round" />
      <path d="M50 72 V75" stroke="white" strokeWidth="2" strokeLinecap="round" />
      <path d="M25 50 H28" stroke="white" strokeWidth="2" strokeLinecap="round" />
      <path d="M72 50 H75" stroke="white" strokeWidth="2" strokeLinecap="round" />
    </g>
  </svg>
);

const Navbar: React.FC = () => {
  const { user, logout, deleteAccount } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [isOpen, setIsOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);

  const fetchUnreadCount = async () => {
      if (user) {
          try {
              const notifs = await api.notifications.getAll();
              const unread = notifs.filter((n: any) => !n.isRead).length;
              setUnreadCount(unread);
          } catch(e) {
              console.error(e);
          }
      }
  };

  useEffect(() => {
      fetchUnreadCount();
  }, [user, location]);

  const handleLogout = () => {
    logout();
    setIsOpen(false);
    navigate('/');
  };

  const handleDeleteAccount = async () => {
      const confirm = window.confirm("Are you sure you want to delete your account? This action cannot be undone.");
      if (confirm) {
          try {
              await deleteAccount();
              setIsOpen(false);
              navigate('/');
              alert("Account deleted successfully.");
          } catch (e) {
              alert("Failed to delete account. Please try again.");
          }
      }
  };

  if (user?.role === UserRole.STAFF) {
      return (
        <nav className="bg-slate-900 text-white shadow-lg sticky top-0 z-50 border-b border-indigo-500">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex items-center justify-between h-16">
              <div className="flex items-center space-x-2">
                <UniPartyLogo />
                <span className="text-xl font-bold tracking-wider">Staff Scanner</span>
              </div>

              <div className="flex items-center space-x-4">
                <Link 
                    to="/scanner" 
                    className="flex items-center px-3 py-2 rounded-md text-sm font-bold bg-indigo-600 hover:bg-indigo-500 transition"
                >
                    <ScanLine className="h-4 w-4 mr-2" /> Scanner
                </Link>
                <button 
                    onClick={handleLogout}
                    className="p-2 text-indigo-300 hover:text-white transition"
                    title="Logout"
                >
                    <LogOut className="h-6 w-6" />
                </button>
              </div>
            </div>
          </div>
        </nav>
      );
  }

  return (
    <nav className="bg-indigo-950 text-white shadow-lg sticky top-0 z-50 border-b border-indigo-900/50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <Link to="/" className="flex items-center space-x-2" onClick={() => setIsOpen(false)}>
            <UniPartyLogo />
            <span className="text-xl font-bold tracking-wider">UniParty</span>
          </Link>

          <div className="flex items-center space-x-4">
              {user && (
                  <Link to="/notifications" className="relative p-2 text-indigo-200 hover:text-white transition">
                      <Bell className="w-6 h-6" />
                      {unreadCount > 0 && (
                          <span className="absolute top-1 right-1 block h-4 w-4 rounded-full bg-red-500 ring-2 ring-indigo-950 text-[10px] font-bold text-center flex items-center justify-center">
                              {unreadCount}
                          </span>
                      )}
                  </Link>
              )}

              <div className="md:hidden">
                <button
                  onClick={() => setIsOpen(!isOpen)}
                  className="inline-flex items-center justify-center p-2 rounded-md text-indigo-200 hover:text-white hover:bg-indigo-900 focus:outline-none transition-colors"
                >
                  <span className="sr-only">Open main menu</span>
                  {isOpen ? <X className="h-8 w-8" /> : <Menu className="h-8 w-8" />}
                </button>
              </div>

              <div className="hidden md:flex">
                  <button
                    onClick={() => setIsOpen(!isOpen)}
                    className="inline-flex items-center justify-center p-2 rounded-md text-indigo-200 hover:text-white hover:bg-indigo-900 focus:outline-none transition-colors"
                  >
                     <Menu className="h-8 w-8" />
                  </button>
              </div>
          </div>
        </div>
      </div>

      {isOpen && (
        <div className="absolute top-16 right-0 w-full sm:w-80 z-50 bg-gray-800 border-b-2 border-l-2 border-gray-700 shadow-2xl animate-in slide-in-from-top-2 duration-200 sm:rounded-bl-xl max-h-[calc(100vh-4rem)] overflow-y-auto">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3 text-white">

            <Link 
                to="/" 
                className="block px-3 py-3 rounded-md text-base font-medium hover:bg-gray-700 transition"
                onClick={() => setIsOpen(false)}
            >
                Events
            </Link>

            {!user && (
              <Link 
                to="/auth" 
                className="block px-3 py-3 rounded-md text-base font-medium bg-indigo-600 hover:bg-indigo-500 mt-2 text-center shadow-md transition"
                onClick={() => setIsOpen(false)}
              >
                Login / Register
              </Link>
            )}

            {user && user.role === UserRole.STUDENTE && (
               <>
                 <Link 
                    to="/search" 
                    className="flex items-center px-3 py-3 rounded-md text-base font-medium hover:bg-gray-700 transition"
                    onClick={() => setIsOpen(false)}
                 >
                    <Search className="h-5 w-5 mr-3 text-indigo-400" /> Search Associations
                 </Link>
                 <Link 
                    to="/wallet" 
                    className="flex items-center px-3 py-3 rounded-md text-base font-medium hover:bg-gray-700 transition"
                    onClick={() => setIsOpen(false)}
                 >
                    <Ticket className="h-5 w-5 mr-3 text-yellow-400" /> My Wallet
                 </Link>
                 <Link 
                    to="/favorites" 
                    className="flex items-center px-3 py-3 rounded-md text-base font-medium hover:bg-gray-700 transition"
                    onClick={() => setIsOpen(false)}
                 >
                    <Heart className="h-5 w-5 mr-3 text-red-400" /> Favorite Events
                 </Link>
               </>
            )}

            {user && user.role === UserRole.ASSOCIAZIONE && (
               <>
                 <Link 
                    to="/dashboard" 
                    className="flex items-center px-3 py-3 rounded-md text-base font-medium hover:bg-gray-700 transition"
                    onClick={() => setIsOpen(false)}
                 >
                    <LayoutDashboard className="h-5 w-5 mr-3 text-indigo-400" /> Dashboard
                 </Link>
                 <Link 
                    to="/dashboard?tab=create" 
                    className="flex items-center px-3 py-3 rounded-md text-base font-medium hover:bg-gray-700 transition"
                    onClick={() => setIsOpen(false)}
                 >
                    <PlusCircle className="h-5 w-5 mr-3 text-green-400" /> Add Event
                 </Link>
                 <Link 
                    to="/scanner" 
                    className="flex items-center px-3 py-3 rounded-md text-base font-medium hover:bg-indigo-600 bg-indigo-700 mt-1 transition shadow-inner"
                    onClick={() => setIsOpen(false)}
                 >
                    <ScanLine className="h-5 w-5 mr-3 text-cyan-300" /> Scan Voucher
                 </Link>
               </>
             )}

             {user && user.role === UserRole.ADMIN && (
                 <Link 
                    to="/admin" 
                    className="flex items-center px-3 py-3 rounded-md text-base font-medium hover:bg-gray-700 bg-gray-900 mt-1 transition shadow-inner border border-indigo-900"
                    onClick={() => setIsOpen(false)}
                 >
                    <Shield className="h-5 w-5 mr-3 text-red-500" /> Admin Dashboard
                 </Link>
             )}

             {user && (
               <div className="border-t border-gray-700 mt-2 pt-2 pb-1">
                 <div className="flex items-center px-3 mb-2 pt-2">
                    <div className="flex-shrink-0">
                       <div className="h-10 w-10 rounded-full bg-indigo-600 flex items-center justify-center border border-indigo-400 shadow-sm">
                         <UserIcon className="h-6 w-6 text-indigo-100" />
                       </div>
                    </div>
                    <div className="ml-3 overflow-hidden">
                      <div className="text-base font-bold leading-none text-white truncate">{user.name}</div>
                      <div className="text-xs font-medium leading-none text-indigo-300 mt-1 capitalize">{user.role}</div>
                    </div>
                 </div>

                 <Link 
                    to="/profile" 
                    className="block px-3 py-2 rounded-md text-base font-medium hover:bg-gray-700 transition text-indigo-100 hover:text-white"
                    onClick={() => setIsOpen(false)}
                 >
                    My Profile
                 </Link>

                 <Link 
                    to="/notifications" 
                    className="block px-3 py-2 rounded-md text-base font-medium hover:bg-gray-700 transition text-indigo-100 hover:text-white flex items-center justify-between"
                    onClick={() => setIsOpen(false)}
                 >
                    <span>Notifications</span>
                    {unreadCount > 0 && <span className="bg-red-600 text-white text-xs px-2 py-0.5 rounded-full">{unreadCount}</span>}
                 </Link>
               </div>
             )}

             <div className="border-t border-gray-700 mt-2 pt-2">
                <Link 
                    to="/support" 
                    className="flex items-center px-3 py-2 rounded-md text-base font-medium hover:bg-gray-700 transition text-gray-300 hover:text-white"
                    onClick={() => setIsOpen(false)}
                 >
                    <HelpCircle className="h-4 w-4 mr-3" /> Support
                 </Link>
                 <Link 
                    to="/terms" 
                    className="flex items-center px-3 py-2 rounded-md text-base font-medium hover:bg-gray-700 transition text-gray-300 hover:text-white"
                    onClick={() => setIsOpen(false)}
                 >
                    <FileText className="h-4 w-4 mr-3" /> Termini & Condizioni
                 </Link>
                 <Link 
                    to="/privacy" 
                    className="flex items-center px-3 py-2 rounded-md text-base font-medium hover:bg-gray-700 transition text-gray-300 hover:text-white"
                    onClick={() => setIsOpen(false)}
                 >
                    <Shield className="h-4 w-4 mr-3" /> Privacy Policy
                 </Link>
             </div>

             {user && (
                <div className="border-t border-gray-700 mt-2 pt-2 pb-2">
                    <button
                        onClick={handleLogout}
                        className="w-full text-left block px-3 py-2 rounded-md text-base font-medium text-white hover:bg-gray-700 transition mb-1"
                    >
                        Logout
                    </button>

                    <button
                        onClick={handleDeleteAccount}
                        className="w-full text-left flex items-center px-3 py-2 rounded-md text-base font-medium text-red-400 hover:text-red-300 hover:bg-red-900/30 transition"
                    >
                        <Trash2 className="h-4 w-4 mr-2" />
                        Delete Account
                    </button>
                </div>
             )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { Link } from 'react-router-dom';
import { Calendar, MapPin, Users, Flame, Heart } from 'lucide-react';
import { Event, UserRole } from '../types';
import { useAuth } from '../context/AuthContext';

interface EventCardProps {
  event: Event;
}

const EventCard: React.FC<EventCardProps> = ({ event }) => {
  const { user, toggleFavorite } = useAuth();

  const eventDate = new Date(event.date).toLocaleDateString('it-IT', {
    weekday: 'short',
    day: 'numeric',
    month: 'short',
  });

  const priceInCents = Math.round(Number(event.price) * 100);
  const isFree = priceInCents === 0;
  const feeInCents = isFree ? 0 : 40;
  const totalInCents = priceInCents + feeInCents;
  const finalPrice = totalInCents / 100;

  const soldRatio = event.ticketsSold / event.maxCapacity;
  const isSoldOut = soldRatio >= 1;
  const isAlmostSoldOut = soldRatio >= 0.6 && !isSoldOut;

  const organizationId = typeof event.organization === 'string' 
    ? event.organization 
    : event.organization?._id;

  const isOwner = user && organizationId && user._id === organizationId;
  const showExactNumbers = isOwner;

  const isFavorite = user?.favorites?.includes(event._id) || false;

  const handleFavoriteClick = (e: React.MouseEvent) => {
      e.preventDefault(); 
      e.stopPropagation();
      if (user && user.role === UserRole.STUDENTE) {
          toggleFavorite(event._id);
      } else if (!user) {
          alert("Accedi come studente per salvare i preferiti.");
      }
  };

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    e.currentTarget.src = "https://picsum.photos/800/400?random=999"; 
  };

  return (
    <Link to={`/events/${event._id}`} className="group relative block h-full">
      <div className="bg-gray-800 rounded-xl shadow-md overflow-hidden hover:shadow-xl transition-all duration-300 border border-gray-700 h-full flex flex-col">
        <div className="relative h-48 overflow-hidden">
          <img
            src={event.image}
            alt={event.title}
            onError={handleImageError}
            className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-500"
          />
          <div className="absolute top-4 right-4 flex gap-2">
               {(!user || user.role === UserRole.STUDENTE) && (
                   <button 
                        onClick={handleFavoriteClick}
                        className="bg-gray-900/80 backdrop-blur-sm p-2 rounded-full shadow-sm hover:scale-110 transition z-10"
                   >
                       <Heart 
                          className={`w-5 h-5 ${isFavorite ? 'fill-red-500 text-red-500' : 'text-gray-400 hover:text-red-500'}`} 
                        />
                   </button>
               )}
               {isOwner && (
                   <div className="bg-indigo-900/80 backdrop-blur-sm px-3 py-1 rounded-full text-pink-400 font-bold text-sm shadow-sm flex items-center">
                       <Heart className="w-3 h-3 mr-1 fill-pink-400" />
                       {event.favoritesCount || 0}
                   </div>
               )}
               <div className="bg-indigo-900/80 backdrop-blur-sm px-3 py-1 rounded-full text-indigo-300 font-bold text-sm shadow-sm flex items-center">
                    {isFree ? 'Free' : `€${finalPrice.toFixed(2)}`}
               </div>
          </div>
        </div>

        <div className="p-5 flex-1 flex flex-col">
          <div className="text-xs font-semibold text-indigo-400 mb-2 uppercase tracking-wide">
            {typeof event.organization === 'string' ? 'Association' : (event.organization?.name || 'Association')}
          </div>
          <h3 className="text-lg font-bold text-white mb-2 group-hover:text-indigo-400 transition-colors">
            {event.title}
          </h3>
          <p className="text-gray-400 text-sm mb-4 line-clamp-2 flex-1">
            {event.description}
          </p>

          <div className="space-y-2 text-sm text-gray-400 mt-auto pt-4 border-t border-gray-700">
            <div className="flex items-center">
              <Calendar className="h-4 w-4 mr-2 text-indigo-500" />
              <span>{eventDate} • {event.time}</span>
            </div>
            <div className="flex items-center">
              <MapPin className="h-4 w-4 mr-2 text-indigo-500" />
              <span className="truncate">{event.location}</span>
            </div>
            <div className="flex items-center">
              <Users className="h-4 w-4 mr-2 text-indigo-500" />
              <span>
                {showExactNumbers 
                  ? `${event.ticketsSold}/${event.maxCapacity} Prenotati`
                  : isSoldOut 
                    ? 'Sold Out' 
                    : isAlmostSoldOut 
                      ? 'Ultimi posti!' 
                      : 'Voucher disponibili'}
              </span>
            </div>
            {isAlmostSoldOut && !isSoldOut && (
               <div className="flex items-center text-orange-400 text-xs font-bold mt-1">
                 <Flame className="h-3 w-3 mr-1" />
                 Selling fast!
               </div>
            )}
          </div>
        </div>
      </div>
    </Link>
  );
};

export default EventCard;

import React, { useEffect, useState } from 'react';
import { Event, EventCategory } from '../types';
import { api } from '../services/api';
import EventCard from '../components/EventCard';
import { Search, Filter, X, Calendar, Tag, DollarSign, Check } from 'lucide-react';

const Home: React.FC = () => {
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  const [showFilters, setShowFilters] = useState(false);
  const [selectedTime, setSelectedTime] = useState<'all' | 'today' | 'tomorrow' | 'week' | 'weekend'>('all');
  const [selectedPrice, setSelectedPrice] = useState<'all' | 'free' | 'paid'>('all');
  const [selectedCategory, setSelectedCategory] = useState<'all' | EventCategory>('all');

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const data = await api.events.getAll();
        setEvents(data);
      } catch (error) {
        console.error("Failed to fetch events", error);
      } finally {
        setLoading(false);
      }
    };
    fetchEvents();
  }, []);

  const filteredEvents = events.filter(e => {
    const lowerSearch = searchTerm.toLowerCase();
    const orgName = typeof e.organization === 'object' && e.organization !== null && 'name' in e.organization
      ? e.organization.name.toLowerCase() 
      : '';
    const matchesSearch = 
      e.title.toLowerCase().includes(lowerSearch) ||
      e.location.toLowerCase().includes(lowerSearch) ||
      orgName.includes(lowerSearch);

    if (!matchesSearch) return false;
    if (selectedCategory !== 'all' && e.category !== selectedCategory) return false;
    if (selectedPrice === 'free' && e.price > 0) return false;
    if (selectedPrice === 'paid' && e.price === 0) return false;

    if (selectedTime !== 'all') {
        const eventDate = new Date(e.date);
        const today = new Date();
        today.setHours(0,0,0,0);
        const tomorrow = new Date(today);
        tomorrow.setDate(today.getDate() + 1);
        const eventDateNoTime = new Date(eventDate);
        eventDateNoTime.setHours(0,0,0,0);

        if (selectedTime === 'today') {
            if (eventDateNoTime.getTime() !== today.getTime()) return false;
        } else if (selectedTime === 'tomorrow') {
            if (eventDateNoTime.getTime() !== tomorrow.getTime()) return false;
        } else if (selectedTime === 'week') {
            const nextWeek = new Date(today);
            nextWeek.setDate(today.getDate() + 7);
            if (eventDateNoTime < today || eventDateNoTime > nextWeek) return false;
        } else if (selectedTime === 'weekend') {
            const day = eventDate.getDay(); 
            const isWeekendDay = day === 0 || day === 5 || day === 6;
            const nextWeek = new Date(today);
            nextWeek.setDate(today.getDate() + 7);
            if (!isWeekendDay || eventDateNoTime > nextWeek || eventDateNoTime < today) return false;
        }
    }
    return true;
  });

  const clearFilters = () => {
      setSelectedTime('all');
      setSelectedPrice('all');
      setSelectedCategory('all');
  };

  const hasActiveFilters = selectedTime !== 'all' || selectedPrice !== 'all' || selectedCategory !== 'all';

  return (
    <div className="min-h-screen bg-gray-900">
      <div className="bg-indigo-950 text-white py-12 md:py-16 relative overflow-hidden border-b border-indigo-900/50">
        <div className="absolute top-0 left-0 w-full h-full overflow-hidden opacity-10 pointer-events-none">
            <div className="absolute -top-20 -left-20 w-96 h-96 bg-pink-500 rounded-full mix-blend-multiply filter blur-3xl"></div>
            <div className="absolute -bottom-20 -right-20 w-96 h-96 bg-blue-500 rounded-full mix-blend-multiply filter blur-3xl"></div>
        </div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center relative z-10">
          <h1 className="text-3xl md:text-5xl font-bold mb-4">Find Your Next UniParty</h1>
          <p className="text-lg text-indigo-200 mb-8 max-w-2xl mx-auto">
            The official platform for university events. Exclusive parties, networking, and fun.
          </p>

          <div className="max-w-2xl mx-auto relative flex items-center">
            <div className="relative flex-grow">
                <input
                  type="text"
                  placeholder="Search events by name, location or association..."
                  className="w-full pl-6 pr-12 py-4 rounded-l-full bg-gray-800 text-white focus:outline-none shadow-lg border-r border-gray-700"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
                <div className="absolute right-4 top-1/2 transform -translate-y-1/2">
                    <Search className="h-5 w-5 text-gray-500" />
                </div>
            </div>
            <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`px-6 py-4 rounded-r-full font-semibold flex items-center transition shadow-lg ${showFilters || hasActiveFilters ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-300 hover:bg-gray-700'}`}
            >
                <Filter className="h-5 w-5 mr-2" />
                Filters
            </button>
          </div>
        </div>
      </div>

      {showFilters && (
          <div className="bg-gray-800 border-b border-gray-700 shadow-sm animate-in slide-in-from-top-2 duration-200">
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
                  <div className="flex justify-between items-center mb-4">
                      <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider">Filter Events</h3>
                      <button onClick={clearFilters} className="text-sm text-indigo-400 hover:text-indigo-300 hover:underline">
                          Reset All
                      </button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div>
                          <label className="block text-sm font-medium text-gray-200 mb-2 flex items-center">
                              <Calendar className="w-4 h-4 mr-2 text-indigo-500" /> Time
                          </label>
                          <div className="flex flex-wrap gap-2">
                              {['all', 'today', 'tomorrow', 'week', 'weekend'].map((t) => (
                                  <button
                                    key={t}
                                    onClick={() => setSelectedTime(t as any)}
                                    className={`px-3 py-1.5 rounded-full text-sm border transition ${selectedTime === t ? 'bg-indigo-900 border-indigo-700 text-indigo-100 font-medium' : 'bg-gray-700 border-gray-600 text-gray-300 hover:bg-gray-600'}`}
                                  >
                                      {t === 'all' ? 'Any Date' : t.charAt(0).toUpperCase() + t.slice(1)}
                                  </button>
                              ))}
                          </div>
                      </div>

                      <div>
                          <label className="block text-sm font-medium text-gray-200 mb-2 flex items-center">
                              <Tag className="w-4 h-4 mr-2 text-indigo-500" /> Category
                          </label>
                          <div className="flex flex-wrap gap-2">
                              <button
