    </div>
  );
};

export default Home;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { UserRole } from '../types';
import { api } from '../services/api';
import { Eye, EyeOff } from 'lucide-react';

const Auth: React.FC = () => {
  const [viewState, setViewState] = useState<'login' | 'register' | 'forgot'>('login');
  const { login, register, isLoading } = useAuth();
  const navigate = useNavigate();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [name, setName] = useState('');
  const [surname, setSurname] = useState('');
  const [description, setDescription] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.STUDENTE);
  const [error, setError] = useState('');
  const [infoMessage, setInfoMessage] = useState(''); 
  const [acceptedTerms, setAcceptedTerms] = useState(false);

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isValidPassword = (password: string) => {
    if (password.length < 6) return false;
    if (!/[A-Z]/.test(password)) return false;
    if (!/[0-9]/.test(password)) return false;
    if (!/[!@#$%^&*(),.?":{}|<>]/.test(password)) return false;
    return true;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setInfoMessage('');

    if (viewState === 'forgot') {
        if (!email || !isValidEmail(email)) {
            setError("Please enter a valid email.");
            return;
        }
        try {
            await api.auth.forgotPassword(email);
            setInfoMessage("Se l'email esiste, riceverai un link di recupero a breve.");
        } catch (err: any) {
            setError(err.message || 'Failed to request password reset');
        }
        return;
    }

    if (!email || !password) {
        setError("Please fill in all fields");
        return;
    }

    if (!isValidEmail(email)) {
        setError("Please enter a valid real email address.");
        return;
    }

    if (viewState === 'register') {
        if (!isValidPassword(password)) {
            setError("Password must be at least 6 characters long and contain at least: 1 uppercase letter, 1 number, and 1 special character.");
            return;
        }
        if (!acceptedTerms) {
            setError("Devi accettare i Termini e Condizioni e la Privacy Policy per registrarti.");
            return;
        }
    }

    try {
      if (viewState === 'login') {
        await login(email, password);
      } else {
        await register({
          email,
          password, 
          name,
          role,
          ...(role === UserRole.STUDENTE ? { surname } : { description })
        });
      }
      navigate('/');
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    }
  };

  const toggleMode = () => {
      setViewState(viewState === 'login' ? 'register' : 'login');
      setError('');
      setInfoMessage('');
      setAcceptedTerms(false);
  };

  const switchToForgot = () => {
      setViewState('forgot');
      setError('');
      setInfoMessage('');
  };

  const backToLogin = () => {
      setViewState('login');
      setError('');
      setInfoMessage('');
  };

  return (
    <div className="min-h-[calc(100vh-64px)] flex items-center justify-center bg-gray-900 px-4">
      <div className="bg-gray-800 rounded-2xl shadow-xl w-full max-w-md overflow-hidden border border-gray-700">
        <div className="px-8 py-8">
            <h2 className="text-3xl font-bold text-center text-white mb-2">
              {viewState === 'login' && 'Welcome Back'}
              {viewState === 'register' && 'Join UniParty'}
              {viewState === 'forgot' && 'Recupero Password'}
            </h2>
            <p className="text-center text-gray-400 mb-8">
              {viewState === 'login' && 'Login to access your vouchers'}
              {viewState === 'register' && 'Create an account to start partying'}
              {viewState === 'forgot' && 'Inserisci la tua email per reimpostare la password'}
            </p>

            {error && (
                <div className="bg-red-950/30 text-red-400 p-3 rounded-lg mb-4 text-sm text-center border border-red-900/50">
                    {error}
                </div>
            )}

            {infoMessage && (
                <div className="bg-green-950/30 text-green-400 p-3 rounded-lg mb-4 text-sm text-center border border-green-900/50">
                    {infoMessage}
                </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4">

              {viewState === 'register' && (
                <div className="flex bg-gray-900 p-1 rounded-lg mb-6 border border-gray-700">
                  <button
                    type="button"
                    className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${role === UserRole.STUDENTE ? 'bg-gray-800 shadow text-indigo-400 border border-gray-700' : 'text-gray-500'}`}
                    onClick={() => setRole(UserRole.STUDENTE)}
                  >
                    Student
                  </button>
                  <button
                    type="button"
                    className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${role === UserRole.ASSOCIAZIONE ? 'bg-gray-800 shadow text-indigo-400 border border-gray-700' : 'text-gray-500'}`}
                    onClick={() => setRole(UserRole.ASSOCIAZIONE)}
                  >
                    Association
                  </button>
                </div>
              )}

              {viewState === 'register' && (
                  <>
                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-1">Name {role === UserRole.ASSOCIAZIONE ? '(Organization)' : ''}</label>
                        <input
                            type="text"
                            className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            required
                        />
                    </div>
                    {role === UserRole.STUDENTE && (
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Surname</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={surname}
                                onChange={(e) => setSurname(e.target.value)}
                                required
                            />
                        </div>
                    )}
                    {role === UserRole.ASSOCIAZIONE && (
                         <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Description</label>
                            <textarea
                                className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                rows={2}
                                required
                            />
                        </div>
                    )}
                  </>
              )}

              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">Email</label>
                <input
                  type="email"
                  className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg text-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                />
              </div>

              {viewState !== 'forgot' && (
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Password</label>
                    <div className="relative">
                        <input
                        type={showPassword ? 'text' : 'password'}
                        className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg text-white focus:ring-2 focus:ring-indigo-500 outline-none pr-10"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        required
                        />
                        <button
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-white focus:outline-none"
                        >
                            {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                        </button>
                    </div>
                    {viewState === 'register' && (
                        <p className="text-xs text-gray-500 mt-1">
                            Min. 6 chars, 1 uppercase, 1 number, 1 special char.
                        </p>
                    )}
                    {viewState === 'login' && (
                        <div className="text-right mt-1">
                            <button type="button" onClick={switchToForgot} className="text-xs text-indigo-400 hover:underline">
                                Password dimenticata?
                            </button>
                        </div>
                    )}
                  </div>
              )}

              {viewState === 'register' && (
                  <div className="flex items-start mt-4">
                      <div className="flex items-center h-5">
                          <input
                              id="terms"
                              name="terms"
                              type="checkbox"
                              checked={acceptedTerms}
                              onChange={(e) => setAcceptedTerms(e.target.checked)}
                              className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-gray-600 bg-gray-700 rounded cursor-pointer"
                              required
                          />
                      </div>
                      <div className="ml-3 text-sm">
                          <label htmlFor="terms" className="font-medium text-gray-400">
                              Ho letto e accetto i <Link to="/terms" className="text-indigo-400 hover:underline">Termini e Condizioni</Link> e la <Link to="/privacy" className="text-indigo-400 hover:underline">Privacy Policy</Link>.
                          </label>
                      </div>
                  </div>
              )}

              <button
                type="submit"
                disabled={isLoading || (viewState === 'register' && !acceptedTerms)}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-lg transition-colors shadow-lg disabled:opacity-50 disabled:cursor-not-allowed mt-6"
              >
                {isLoading ? 'Processing...' : (
                    viewState === 'login' ? 'Login' : 
                    viewState === 'register' ? 'Sign Up' : 'Invia Link di Recupero'
                )}
              </button>
            </form>
        </div>
        <div className="bg-gray-900/50 px-8 py-4 text-center border-t border-gray-700">
            {viewState === 'forgot' ? (
                <button 
                    onClick={backToLogin}
                    className="text-indigo-400 font-semibold hover:underline text-sm"
                >
                    Torna al Login
                </button>
            ) : (
                <p className="text-sm text-gray-400">
                    {viewState === 'login' ? "Don't have an account? " : "Already have an account? "}
                    <button 
                        onClick={toggleMode}
                        className="text-indigo-400 font-semibold hover:underline"
                    >
                        {viewState === 'login' ? 'Register' : 'Login'}
                    </button>
                </p>
            )}
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import { UserRole, EventCategory, Event, User } from '../types';
import { useNavigate, useSearchParams, Link } from 'react-router-dom';
import { 
    AlertTriangle, CheckCircle, Plus, DollarSign, Image as ImageIcon, Users, List, X, Tag, Clock, 
    ShieldCheck, Lock, Info, Upload, FileText, TrendingUp, Briefcase, Ticket, LayoutDashboard, Calendar, Settings, GraduationCap, UserPlus, Key, Trash2
} from 'lucide-react';

const Dashboard: React.FC = () => {
  const { user, refreshUser } = useAuth();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [activeTab, setActiveTab] = useState<'overview' | 'create' | 'staff'>('overview');
  const [isConnecting, setIsConnecting] = useState(false);
  const [assocEvents, setAssocEvents] = useState<Event[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);

  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [price, setPrice] = useState('0');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('22:00');
  const [location, setLocation] = useState('');
  const [image, setImage] = useState('');
  const [maxCapacity, setMaxCapacity] = useState('100');
  const [category, setCategory] = useState<EventCategory>(EventCategory.PARTY);

  const [requiresAcademicData, setRequiresAcademicData] = useState(false); 
  const [scanType, setScanType] = useState<'entry_only' | 'entry_exit'>('entry_only');

  const [prLists, setPrLists] = useState<string[]>([]);
  const [currentPrInput, setCurrentPrInput] = useState('');

  const [creatingEvent, setCreatingEvent] = useState(false);
  const [targetStatus, setTargetStatus] = useState<'active' | 'draft'>('active');

  const [staffEmail, setStaffEmail] = useState('');
  const [staffPassword, setStaffPassword] = useState('');
  const [isManagingStaff, setIsManagingStaff] = useState(false);
  const [staffList, setStaffList] = useState<User[]>([]);
  const [loadingStaff, setLoadingStaff] = useState(false);

  useEffect(() => {
    const tabParam = searchParams.get('tab');
    if (tabParam === 'create') setActiveTab('create');
    else if (tabParam === 'staff') setActiveTab('staff');
    else setActiveTab('overview');
  }, [searchParams]);

  useEffect(() => {
    if (user && user.role === UserRole.ASSOCIAZIONE) {
      setLoadingEvents(true);
      api.events.getByOrgId(user._id)
        .then(setAssocEvents)
        .catch(console.error)
        .finally(() => setLoadingEvents(false));
    }
  }, [user]);

  useEffect(() => {
    if (activeTab === 'staff' && user && user.role === UserRole.ASSOCIAZIONE) {
        fetchStaff();
    }
  }, [activeTab, user]);

  const fetchStaff = async () => {
    setLoadingStaff(true);
    try {
        const data = await api.auth.getStaffAccounts();
        setStaffList(data);
    } catch (e) {
        console.error("Fetch staff error", e);
    } finally {
        setLoadingStaff(false);
    }
  };

  if (!user || user.role !== UserRole.ASSOCIAZIONE) {
    return <div className="p-8 bg-gray-900 min-h-screen text-white">Access Denied</div>;
  }

  const totalEvents = assocEvents.length;
  const totalTicketsSold = assocEvents.reduce((acc, curr) => acc + curr.ticketsSold, 0);
  const totalRevenue = assocEvents.reduce((acc, curr) => acc + (curr.ticketsSold * curr.price), 0);

  const handleTabChange = (tab: 'overview' | 'create' | 'staff') => {
      setActiveTab(tab);
      setSearchParams(tab !== 'overview' ? { tab } : {});
  };

  const handleStripeConnect = async () => {
    setIsConnecting(true);
    try {
      const link = await api.stripe.createConnectAccount(user._id);
      if (link) {
          window.location.href = link;
      } else {
           const confirmed = window.confirm("Simulating Stripe Onboarding. Click OK to finish.");
           if(confirmed) {
               await api.stripe.finalizeOnboarding(user._id);
               refreshUser();
           }
      }
    } catch (error) {
      console.error(error);
      alert("Failed to connect Stripe");
    } finally {
      setIsConnecting(false);
    }
  };

  const handleAddPrList = () => {
      if (currentPrInput.trim() && !prLists.includes(currentPrInput.trim())) {
          setPrLists([...prLists, currentPrInput.trim()]);
          setCurrentPrInput('');
      }
  };

  const handleRemovePrList = (listToRemove: string) => {
      setPrLists(prLists.filter(list => list !== listToRemove));
  };

  const handleImageUpload = () => {
    const widget = window.cloudinary.createUploadWidget(
      {
        cloudName: 'db3bj2bgg',
        uploadPreset: 'wii81qid',
        sources: ['local', 'url', 'camera', 'instagram'],
        multiple: false,
        maxFiles: 1,
        clientAllowedFormats: ["image"],
      },
      (error: any, result: any) => {
        if (!error && result && result.event === "success") {
          setImage(result.info.secure_url);
        }
      }
    );
    widget.open();
  };

  const handleCreateEvent = async (e: React.FormEvent) => {
    e.preventDefault();
    const cleanPriceStr = (user.stripeOnboardingComplete ? price : '0').toString().replace(',', '.');
    const tempPrice = parseFloat(cleanPriceStr);
    const numericPrice = isNaN(tempPrice) ? 0 : Number(tempPrice.toFixed(2));
    if (isNaN(numericPrice) || numericPrice < 0) {
        alert("Prezzo non valido.");
        return;
    }
    if (!image) {
        alert("Per favore carica un'immagine per l'evento.");
        return;
    }
    setCreatingEvent(true);
    try {
        const newEvent = await api.events.create({
            title, description, longDescription: description,
            date, time, location, image,
            maxCapacity: parseInt(maxCapacity),
            price: numericPrice, category, prLists,
            status: targetStatus,
            requiresMatricola: requiresAcademicData, 
            requiresCorsoStudi: requiresAcademicData, 
            scanType
        }, user);
        if (targetStatus === 'draft') {
            alert("Bozza salvata con successo!");
            navigate(`/events/${newEvent._id}`);
        } else {
            alert("Evento pubblicato con successo!");
            navigate('/');
        }
    } catch (e: any) {
        console.error(e);
        alert("Errore creazione evento: " + (e.message || "Unknown"));
    } finally {
        setCreatingEvent(false);
    }
  };

  const handleManageStaff = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!staffEmail || !staffPassword) return;
      setIsManagingStaff(true);
      try {
          await api.auth.createStaffAccount({ email: staffEmail, password: staffPassword });
          alert("Account Staff gestito con successo!");
          setStaffEmail('');
          setStaffPassword('');
          fetchStaff();
      } catch (e: any) {
          alert("Errore: " + e.message);
      } finally {
          setIsManagingStaff(false);
      }
  };

  const handleDeleteStaff = async (id: string) => {
    if (!window.confirm("Sei sicuro di voler eliminare questo account staff?")) return;
    try {
        await api.auth.deleteStaffAccount(id);
        setStaffList(staffList.filter(s => s._id !== id));
    } catch (e: any) {
        alert("Errore: " + e.message);
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 py-8 px-4 sm:px-6 lg:px-8 text-white">
       <div className="max-w-5xl mx-auto space-y-6">
           <div className="flex flex-col md:flex-row justify-between items-center gap-4">
               <div>
                   <h1 className="text-3xl font-bold text-white">Dashboard Associazione</h1>
                   <p className="text-gray-400 text-sm mt-1">Benvenuto, {user.name}.</p>
               </div>

               <div className="bg-gray-800 p-1 rounded-xl shadow-sm border border-gray-700 flex">
                   <button
                       onClick={() => handleTabChange('overview')}
                       className={`px-4 py-2 rounded-lg text-sm font-medium transition flex items-center ${activeTab === 'overview' ? 'bg-indigo-900 text-indigo-100' : 'text-gray-400 hover:bg-gray-700'}`}
                   >
                       <LayoutDashboard className="w-4 h-4 mr-2" />
                       Panoramica
                   </button>
                   <button
                       onClick={() => handleTabChange('create')}
                       className={`px-4 py-2 rounded-lg text-sm font-medium transition flex items-center ${activeTab === 'create' ? 'bg-indigo-900 text-indigo-100' : 'text-gray-400 hover:bg-gray-700'}`}
                   >
                       <Plus className="w-4 h-4 mr-2" />
                       Crea Evento
                   </button>
                   <button
                       onClick={() => handleTabChange('staff')}
